document.addEventListener("DOMContentLoaded",function(){const screens={start:document.getElementById("screen-start"),questions:document.getElementById("screen-questions"),processing:document.getElementById("screen-processing"),result:document.getElementById("screen-result")};const questionSlides=document.querySelectorAll(".question-slide");const progressFill=document.getElementById("progress-fill");const currentQuestionSpan=document.getElementById("current-question");const prevButton=document.getElementById("prev-question");const nextButton=document.getElementById("next-question");const resultEssencialCorrida=document.getElementById("result-essencial-corrida");const resultPremiumCorrida=document.getElementById("result-premium-corrida");const resultEssencialTriathlon=document.getElementById("result-essencial-triathlon");const resultPremiumTriathlon=document.getElementById("result-premium-triathlon");const essencialColumn=document.getElementById("essencial-column");const premiumColumn=document.getElementById("premium-column");const conhecerPlanoBtn=document.getElementById("conhecer-plano");let currentQuestion=1;const totalQuestions=questionSlides.length;let userAnswers=[];let totalPoints=0;let selectedModalidade="";function init(){showScreen("start");showQuestion(1);setupEventListeners()}function setupEventListeners(){document.getElementById("start-quiz").addEventListener("click",function(){showScreen("questions")});document.querySelectorAll(".option").forEach(option=>{option.addEventListener("click",function(){selectOption(this);setTimeout(()=>{if(currentQuestion<totalQuestions){goToNextQuestion()}else{processResult()}},300)})});prevButton.addEventListener("click",goToPreviousQuestion);nextButton.addEventListener("click",goToNextQuestion);document.getElementById("refazer-teste").addEventListener("click",resetCalculadora)}function showScreen(screenName){Object.values(screens).forEach(screen=>{screen.classList.remove("active")});screens[screenName].classList.add("active")}function showQuestion(questionNumber){questionSlides.forEach(slide=>{slide.classList.remove("active")});document.getElementById(`question-${questionNumber}`).classList.add("active");currentQuestionSpan.textContent=questionNumber;progressFill.style.width=`${questionNumber/totalQuestions*100}%`;updateNavigationButtons();currentQuestion=questionNumber}function selectOption(optionElement){const parentQuestion=optionElement.closest(".question-slide");parentQuestion.querySelectorAll(".option").forEach(option=>{option.classList.remove("selected")});optionElement.classList.add("selected");const questionIndex=currentQuestion-1;const value=optionElement.dataset.value;const points=parseInt(optionElement.dataset.points);userAnswers[questionIndex]={value:value,points:points};if(currentQuestion===1){selectedModalidade=value}}function goToNextQuestion(){const currentQuestionElement=document.getElementById(`question-${currentQuestion}`);const selectedOption=currentQuestionElement.querySelector(".option.selected");if(!selectedOption){return}if(currentQuestion===totalQuestions){processResult();return}showQuestion(currentQuestion+1)}function goToPreviousQuestion(){if(currentQuestion>1){showQuestion(currentQuestion-1)}}function updateNavigationButtons(){prevButton.disabled=currentQuestion===1;if(currentQuestion===totalQuestions){nextButton.textContent="Ver resultado";nextButton.innerHTML='Ver resultado <i class="fas fa-check-circle"></i>';const currentQuestionElement=document.getElementById(`question-${currentQuestion}`);const selectedOption=currentQuestionElement.querySelector(".option.selected");nextButton.disabled=!selectedOption}else{nextButton.innerHTML='Próximo <i class="fas fa-arrow-right"></i>';nextButton.disabled=false}}function processResult(){showScreen("processing");let pontosEssencial=0;let pontosPremium=0;userAnswers.slice(1).forEach(answer=>{if(answer){if(answer.value==="essencial"){pontosEssencial+=1}else if(answer.value==="premium"){pontosPremium+=1}}});totalPoints={essencial:pontosEssencial,premium:pontosPremium};setTimeout(()=>{showResult()},2e3)}function showResult(){const planoRecomendado=totalPoints.premium>totalPoints.essencial?"premium":"essencial";resultEssencialCorrida.classList.remove("active");resultPremiumCorrida.classList.remove("active");resultEssencialTriathlon.classList.remove("active");resultPremiumTriathlon.classList.remove("active");if(selectedModalidade==="corrida"){if(planoRecomendado==="essencial"){resultEssencialCorrida.classList.add("active");conhecerPlanoBtn.textContent="CONHECER O PLANO ESSENCIAL DE CORRIDA"}else{resultPremiumCorrida.classList.add("active");conhecerPlanoBtn.textContent="CONHECER O PLANO PREMIUM DE CORRIDA"}}else{if(planoRecomendado==="essencial"){resultEssencialTriathlon.classList.add("active");conhecerPlanoBtn.textContent="CONHECER O PLANO ESSENCIAL DE TRIATHLON"}else{resultPremiumTriathlon.classList.add("active");conhecerPlanoBtn.textContent="CONHECER O PLANO PREMIUM DE TRIATHLON"}}essencialColumn.classList.remove("highlighted");premiumColumn.classList.remove("highlighted");if(planoRecomendado==="essencial"){essencialColumn.classList.add("highlighted")}else{premiumColumn.classList.add("highlighted")}conhecerPlanoBtn.href="../index.html#modalidades";showScreen("result")}function resetCalculadora(){currentQuestion=1;userAnswers=[];totalPoints=0;selectedModalidade="";document.querySelectorAll(".option").forEach(option=>{option.classList.remove("selected")});resultEssencialCorrida.classList.remove("active");resultPremiumCorrida.classList.remove("active");resultEssencialTriathlon.classList.remove("active");resultPremiumTriathlon.classList.remove("active");essencialColumn.classList.remove("highlighted");premiumColumn.classList.remove("highlighted");showQuestion(1);showScreen("questions")}init()});